// HasKeyResult applies the HasEdge predicate on the "key_result" edge.
func HasKeyResult() predicate.Todo {
	return predicate.Todo(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.M2O, true, KeyResultTable, KeyResultColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasKeyResultWith applies the HasEdge predicate on the "key_result" edge with a given conditions (other predicates).
func HasKeyResultWith(preds ...predicate.KeyResult) predicate.Todo {
	return predicate.Todo(func(s *sql.Selector) {
		step := newKeyResultStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

